--
-- Name: update_provider_rating(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_provider_rating() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
            BEGIN
                UPDATE providers
                SET 
                    rating = COALESCE((SELECT ROUND(AVG(rating), 1) FROM reviews WHERE provider_id = COALESCE(NEW.provider_id, OLD.provider_id)), 0.0),
                    reviews_count = (SELECT COUNT(*) FROM reviews WHERE provider_id = COALESCE(NEW.provider_id, OLD.provider_id))
                WHERE id = COALESCE(NEW.provider_id, OLD.provider_id);
                RETURN NULL;
            END;
            $$;


